229→        const file = e.target.files[0];
230→        if(file){
231→            setImageFile(file)
232→            const reader = new FileReader();
233→            reader.onloadend = () =>{
234→                setProfilePreview(reader.result)
235→            }
236→            reader.readAsDataURL(file)
237→        }
238→    }
