240→    const slugifyForUsername = (val) =>
241→        String(val || '').toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
242→
243→    const handleNameChangeForSetup = (e) => {
244→        const newName = e.target.value;
245→        setName(newName);
246→        // Auto-suggest username from name if user hasn't manually edited username
247→        if (!setupUsername || setupUsername === slugifyForUsername(name)) {
248→            const suggested = slugifyForUsername(newName);
249→            setSetupUsername(suggested);
250→            checkUsernameDebounced(suggested);
251→        }
252→    };
253→
254→    const handleUsernameChange = (e) => {
255→        const raw = e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '');
256→        setSetupUsername(raw);
257→        checkUsernameDebounced(raw);
258→    };
259→
260→    const checkUsernameDebounced = (uname) => {
261→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
262→        if (!uname || uname.length < 3) {
263→            setUsernameAvailable(null);
264→            return;
265→        }
266→        setUsernameChecking(true);
267→        usernameCheckTimer.current = setTimeout(async () => {
268→            try {
269→                const result = await checkUsernameAvailability(uname);
270→                setUsernameAvailable(result.available);
271→            } catch {
272→                setUsernameAvailable(null);
273→            } finally {
274→                setUsernameChecking(false);
275→            }
276→        }, 400);
277→    };
