292→    const handleSubmit = async(e) =>{
293→        e.stopPropagation();
294→        e.preventDefault();
295→        try {
296→            setUploadingUserData(true)
297→            const formdata = new FormData();
298→            if(imageFile){
299→                formdata.append('image', imageFile);
300→            }
301→            if(bio && name){
302→                formdata.append('name', name)
303→                formdata.append('bio', bio)
304→                if(setupUsername && setupUsername.length >= 3){
305→                    formdata.append('username', setupUsername)
306→                }
307→            }
308→            const {data} = await submitProfileData(formdata, session?.access_token);
309→            // if(data){
310→            //     console.log(data)
311→            // }
312→            setShowWelcomeMessage(true)
313→        } catch (error) {
314→            throw new Error('error uploading data')
