#### Full JSX Structure (WelcomeMessage.jsx - Complete)
```jsx
import './welcomemessage.css';
import { AnimatePresence, motion } from 'framer-motion';
import confetti from "canvas-confetti";
import { useEffect } from 'react';

const WelcomeMessage = ({onClose}) => {
  useEffect(() => {
    const canvas = document.getElementById('my-confetti');
    const myConfetti = confetti.create(canvas, {resize: true})

    const timer = setTimeout(() => {
      myConfetti({
        particleCount: 80,
        spread: 100,
        startVelocity: 25,
        ticks: 500,
        gravity: 0.6,
        scalar: 1.2,
        origin: {x: 0.5, y: 0.4}
      })
    }, 500);

    return () => {
      clearTimeout(timer)
    }
  }, [])

  return(
    <>
      <canvas id='my-confetti' className='confetti-layer'></canvas>
      <AnimatePresence>
        <div className='welcome-message-container'>
          <motion.div 
            initial={{opacity:0 ,scale:0}}
            animate={{
              opacity: 1,
              scale: 1,
              transition: {
                type: "spring",
                stiffness: 180,
                damping: 18,
                duration: 0.35
              }
            }}
            exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.2}}}
            className='welcome-message-child-container'
          >
            {/* Celebration SVG Icon */}
            <svg xmlns="http://www.w3.org/2000/svg" height="80px" width="80px" viewBox="0 0 512 512">
              {/* Colorful celebration/party icon with multiple paths */}
              {/* Colors: red (#E65C64), yellow (#FFC033), teal (#43BFBF) */}
            </svg>

            {/* Welcome Message Text */}
            <div className='welcome-message'>
              "Hey! Thanks for joining <span className='iskrib-word'>Iskrib</span>. From now on, your thoughts can echo to the world."
            </div>

            {/* Close Button */}
            <div onClick={onClose} className='welcome-message-close-bttn'>
              <svg className='welcome-close-svg' xmlns="http://www.w3.org/2000/svg" width="54px" height="54px" viewBox="0 0 24 24" fill="none">
                <path fillRule="evenodd" clipRule="evenodd" d="M12 22C7.28595 22 4.92893 22 3.46447 20.5355C2 19.0711 2 16.714 2 12C2 7.28595 2 4.92893 3.46447 3.46447C4.92893 2 7.28595 2 12 2C16.714 2 19.0711 2 20.5355 3.46447C22 4.92893 22 7.28595 22 12C22 16.714 22 19.0711 20.5355 20.5355C19.0711 22 16.714 22 12 22ZM8.96965 8.96967C9.26254 8.67678 9.73742 8.67678 10.0303 8.96967L12 10.9394L13.9696 8.96969C14.2625 8.6768 14.7374 8.6768 15.0303 8.96969C15.3232 9.26258 15.3232 9.73746 15.0303 10.0303L13.0606 12L15.0303 13.9697C15.3232 14.2625 15.3232 14.7374 15.0303 15.0303C14.7374 15.3232 14.2625 15.3232 13.9696 15.0303L12 13.0607L10.0303 15.0303C9.73744 15.3232 9.26256 15.3232 8.96967 15.0303C8.67678 14.7374 8.67678 14.2626 8.96967 13.9697L10.9393 12L8.96965 10.0303C8.67676 9.73744 8.67676 9.26256 8.96965 8.96967Z" fill="#1C274C"/>
              </svg>
            </div>
          </motion.div>
        </div>
      </AnimatePresence>
    </>
  )
}
export default WelcomeMessage;
